#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct{
	double energy;
	double total_xs;
	double elastic_xs;
	double absorbtion_xs;
	double fission_xs;
	double nu_fission_xs;
} NuclideGridPoint;

typedef struct{
	int nthreads;
	long n_isotopes;
	long n_gridpoints;
	int lookups;
	int HM;
	int grid_type; 
	int hash_bins;
	int particles;
	int simulation_method;
	int binary_mode;
	int kernel_id;
	int platform_id;
	int device_id;
} Inputs;

#define UNIONIZED 0
#define NUCLIDE 1
#define HASH 2
#define HISTORY_BASED 1
#define EVENT_BASED 2
#define NONE 0
#define READ 1
#define WRITE 2
#define SMALL 0
#define LARGE 1
#define XL 2
#define XXL 3

long grid_search_nuclide_kernel( long n, double quarry, const NuclideGridPoint * A, long low, long high)
{
	long lowerLimit = low;
	long upperLimit = high;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while( length > 1 )
	{
		examinationPoint = lowerLimit + ( length / 2 );

		if( A[examinationPoint].energy > quarry )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;

		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

long grid_search_kernel( long n, double quarry, const double * A)
{
	long lowerLimit = 0;
	long upperLimit = n-1;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while( length > 1 )
	{
		examinationPoint = lowerLimit + ( length / 2 );

		if( A[examinationPoint] > quarry )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;

		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

void calculate_micro_xs_kernel(   double p_energy, int nuc, long n_isotopes,
                           long n_gridpoints,
                           const double * egrid, const int * index_data,
                           const NuclideGridPoint * nuclide_grids,
                           long idx, double * xs_vector, int grid_type, int hash_bins ){

	double f;
	NuclideGridPoint low, high_ptr;
	const NuclideGridPoint * low_ptr;

	if( grid_type == NUCLIDE )
	{
		idx = grid_search_nuclide_kernel( n_gridpoints, p_energy, &nuclide_grids[nuc*n_gridpoints], 0, n_gridpoints-1);
		if( idx == n_gridpoints - 1 )
			low_ptr = &nuclide_grids[nuc*n_gridpoints + idx - 1];
		else
			low_ptr = &nuclide_grids[nuc*n_gridpoints + idx];
	}
	else if( grid_type == UNIONIZED) 
	{
		if( index_data[idx * n_isotopes + nuc] == n_gridpoints - 1 )
			low_ptr = &nuclide_grids[nuc*n_gridpoints + index_data[idx * n_isotopes + nuc] - 1];
		else
			low_ptr = &nuclide_grids[nuc*n_gridpoints + index_data[idx * n_isotopes + nuc]];
	}
	else 
	{
		int u_low = index_data[idx * n_isotopes + nuc];
		int u_high;
		if( idx == hash_bins - 1 )
			u_high = n_gridpoints - 1;
		else
			u_high = index_data[(idx+1)*n_isotopes + nuc] + 1;

		double e_low  = nuclide_grids[nuc*n_gridpoints + u_low].energy;
		double e_high = nuclide_grids[nuc*n_gridpoints + u_high].energy;
		int lower;
		if( e_low >= p_energy )
			lower = 0;
		else if( e_high <= p_energy )
			lower = n_gridpoints - 1;
		else
			lower = grid_search_nuclide_kernel( n_gridpoints, p_energy, &nuclide_grids[nuc*n_gridpoints], u_low, u_high);

		if( lower == n_gridpoints - 1 )
			low_ptr = &nuclide_grids[nuc*n_gridpoints + lower - 1];
		else
			low_ptr = &nuclide_grids[nuc*n_gridpoints + lower];
	}

	high_ptr = *(low_ptr + 1);
	low = *low_ptr;

	f = (high_ptr.energy - p_energy) / (high_ptr.energy - low.energy);

	xs_vector[0] = high_ptr.total_xs - f * (high_ptr.total_xs - low.total_xs);
	xs_vector[1] = high_ptr.elastic_xs - f * (high_ptr.elastic_xs - low.elastic_xs);
	xs_vector[2] = high_ptr.absorbtion_xs - f * (high_ptr.absorbtion_xs - low.absorbtion_xs);
	xs_vector[3] = high_ptr.fission_xs - f * (high_ptr.fission_xs - low.fission_xs);
	xs_vector[4] = high_ptr.nu_fission_xs - f * (high_ptr.nu_fission_xs - low.nu_fission_xs);
}

void calculate_macro_xs_kernel( double p_energy, int mat, long n_isotopes,
                         long n_gridpoints, const int * num_nucs,
                         const double * concs,
                         const double * egrid, const int * index_data,
                         const NuclideGridPoint * nuclide_grids,
                         const int * mats,
                         double * macro_xs_vector, int grid_type, int hash_bins, int max_num_nucs ){
	int p_nuc; 
	long idx = -1;	
	double conc; 

	for( int k = 0; k < 5; k++ )
		macro_xs_vector[k] = 0.0;

	if( grid_type == UNIONIZED )
		idx = grid_search_kernel( n_isotopes * n_gridpoints, p_energy, egrid);	
	else if( grid_type == HASH )
	{
		double du = 1.0 / (double)hash_bins;
		idx = (long)(p_energy / du);
	}

	for( int j = 0; j < num_nucs[mat]; j++ )
	{
		double xs_vector[5];
		p_nuc = mats[mat*max_num_nucs + j];
		conc = concs[mat*max_num_nucs + j];
		calculate_micro_xs_kernel( p_energy, p_nuc, n_isotopes,
		                    n_gridpoints, egrid, index_data,
		                    nuclide_grids, idx, xs_vector, grid_type, hash_bins );
		for( int k = 0; k < 5; k++ )
			macro_xs_vector[k] += xs_vector[k] * conc;
	}
}

__kernel void macro_xs_lookup_kernel( Inputs in, int max_num_nucs, 
                                      __global const int * num_nucs,
                                      __global const double * concs,
                                      __global const double * unionized_energy_array,
                                      __global const int * index_grid,
                                      __global const NuclideGridPoint * nuclide_grid,
                                      __global const int * mats,
                                      __global int * verification_array )
{
	int i = get_global_id(0);
	if( i >= in.lookups ) return;

	uint64_t seed = 1070ULL;
	const uint64_t m = 9223372036854775808ULL; 
	const uint64_t a = 2806196910506780709ULL;
	const uint64_t c = 1ULL;

	uint64_t n = 2ULL * (uint64_t)i;
	uint64_t a_new = 1ULL;
	uint64_t c_new = 0ULL;
	while(n > 0) 
	{
		if(n & 1)
		{
			a_new = a_new * a;
			c_new = c_new * a + c;
		}
		c = c * (a + 1);
		a = a * a;
		n = n >> 1;
	}
	seed = (a_new * seed + c_new) % m;

	double p_energy = (double)seed / (double)m;

	seed = (a * seed + c) % m;
	double roll = (double)seed / (double)m;

	double dist[12];
	dist[0]  = 0.140;	
	dist[1]  = 0.052;	
	dist[2]  = 0.275;	
	dist[3]  = 0.134;	
	dist[4]  = 0.154;	
	dist[5]  = 0.064;	
	dist[6]  = 0.066;	
	dist[7]  = 0.055;	
	dist[8]  = 0.008;	
	dist[9]  = 0.015;	
	dist[10] = 0.025;	
	dist[11] = 0.013;

	int mat = 0;
	for( int ii = 0; ii < 12; ii++ )
	{
		double running = 0.0;
		for( int jj = ii; jj > 0; jj-- )
			running += dist[jj];
		if( running > roll )
		{
			mat = ii;
			break;
		}
	}

	double macro_xs_vector[5];
	calculate_macro_xs_kernel(
			p_energy,        
			mat,             
			in.n_isotopes,   
			in.n_gridpoints, 
			num_nucs,     
			concs,        
			unionized_energy_array, 
			index_grid,   
			nuclide_grid, 
			mats,         
			macro_xs_vector, 
			in.grid_type,    
			in.hash_bins,    
			max_num_nucs  
			);

	double max = -1.0;
	int max_idx = 0;
	for(int j = 0; j < 5; j++ )
	{
		if( max < macro_xs_vector[j] )
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}

	verification_array[i] = max_idx + 1;
}
